final:
module top_module(
    input [3:0] int_data,
    output reg [3:0] obf_bcd_data
);always @(int_data) begin
        case (int_data)
            0: obf_bcd_data <= 4'b0000;
            1: obf_bcd_data <= 4'b0001;
            2: obf_bcd_data <= 4'b0010;
            3: obf_bcd_data <= 4'b0011;
            4: obf_bcd_data <= 4'b0100;
            5: obf_bcd_data <= 4'b0101;
            6: obf_bcd_data <= 4'b0110;
            7: obf_bcd_data <= 4'b0111;
            8: obf_bcd_data <= 4'b1000;
            9: obf_bcd_data <= 4'b1001;
            default: obf_bcd_data <= 4'b1010;
        endcase
    end
endmodule
